#include <stdio.h>

int main() {
 int num = 10;
 int *ptr = &num;
 printf("Value at ptr: %d\n", *ptr);
 return 0;
}

#include <stdio.h>

int main() {
 int arr[5] = {10, 20, 30, 40, 50};
 int *ptr = arr;
 printf("Value at ptr: %d\n", *ptr);
 ptr++;
 printf("Value at ptr: %d\n", *ptr);
 return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main() {
 int *ptr = malloc(sizeof(int));
 if (ptr == NULL) {
 printf("Memory allocation failed\n");
 return 1;
 }
 *ptr = 10;
 printf("Value at ptr: %d\n", *ptr);
 free(ptr);
 return 0;
}
